cat > /tmp/check_brand.py << 'PYEOF'
import csv, os, io
DIR = "D:/nexgaios-amazon/品牌分析/热门搜索词"
months = ["2026_02_28","2026_03_31","2026_04_30","2026_05_31","2026_06_30",
          "2025_02_28","2025_06_30"]
def load(mfile):
    with io.open(os.path.join(DIR,f"US_热门搜索词_简单_Month_{mfile}.csv"),encoding="utf-8-sig") as f:
        return list(csv.reader(f))[2:]

print("=== 'karaoke machine' top3 BRAND columns (idx2,3,4) + P1 ASIN ===")
for m in months:
    for r in load(m):
        if len(r)>19 and r[1].strip().lower()=="karaoke machine":
            print(f"  {m[:7]}: brands=[{r[2]} | {r[3]} | {r[4]}]  P1_ASIN={r[8]}")
            break

# Track brand label of B0CCJDG68C and B0D1VJMSQG across all 24 months
print("\n=== Brand-label drift for specific ASINs across 24 months (any word) ===")
import glob
allfiles = sorted(glob.glob(os.path.join(DIR,"US_热门搜索词_简单_Month_*.csv")))
track = {"B0CCJDG68C":set(),"B0D1VJMSQG":set(),"B0CR1R7FKP":set()}
for path in allfiles:
    with io.open(path,encoding="utf-8-sig") as f:
        for r in list(csv.reader(f))[2:]:
            if len(r)<20: continue
            # P1 asin idx8 brand idx2; P2 asin idx12 brand idx3; P3 asin idx16 brand idx4
            for asin_i,brand_i in [(8,2),(12,3),(16,4)]:
                a=r[asin_i].strip()
                if a in track and r[brand_i].strip():
                    track[a].add(r[brand_i].strip())
for a,brands in track.items():
    print(f"  {a}: {sorted(brands)}")
PYEOF
python /tmp/check_brand.py
